class MyDict(dict):
    def __setitem__(self, key, value):
        print(f"Setting {key} = {value}")  # 这个不会被调用
        super().__setitem__(key, value)


d = MyDict(a=1)


from collections import UserDict

class LoggingDict(UserDict):
    def __setitem__(self, key, value):
        print(f"Setting {key} = {value}")
        super().__setitem__(key, value)


d = LoggingDict(a=1)

